+/// Check whether a table-backed SELECT has a GROUP BY clause.
+fn has_group_by(select: &SelectStatement) -> bool {
+    matches!(
+        &select.body.select,
+        SelectCore::Select { group_by, .. } if !group_by.is_empty()
+    )
+}
